'use strict';

// MODULES //

import { isPrimitive as isNonNegativeInteger } from '@stdlib/assert-is-nonnegative-integer';
import isndarrayLike from '@stdlib/assert-is-ndarray-like';
import isPlainObject from '@stdlib/assert-is-plain-object';
import { primitives as isNonNegativeIntegerArray } from '@stdlib/assert-is-nonnegative-integer-array';
import isEmptyCollection from '@stdlib/assert-is-empty-collection';
import hasOwnProp from '@stdlib/assert-has-own-property';
import { factory as contains } from '@stdlib/array-base-assert-contains';
import shape2strides from '@stdlib/ndarray-base-shape2strides';
import buffer from '@stdlib/ndarray-base-buffer';
import numel from '@stdlib/ndarray-base-numel';
import fill from '@stdlib/ndarray-base-fill';
import getDType from '@stdlib/ndarray-dtype';
import getShape from '@stdlib/ndarray-shape';
import getOrder from '@stdlib/ndarray-order';
import ndarray from '@stdlib/ndarray-ctor';
import dtypes from '@stdlib/ndarray-dtypes';
import join from '@stdlib/array-base-join';
import format from '@stdlib/error-tools-fmtprodmsg';


// VARIABLES //

var DTYPES = dtypes( 'boolean_and_generic' );
var isDataType = contains( DTYPES );


// MAIN //

/**
* Creates an ndarray filled with `true` values and having the same shape and data type as a provided ndarray.
*
* @param {ndarray} x - input array
* @param {Options} [options] - function options
* @param {*} [options.dtype] - output array data type (overrides the input array's inferred data type)
* @param {string} [options.order] - specifies whether the output array should be 'row-major' (C-style) or 'column-major' (Fortran-style) (overrides the input array's inferred order)
* @param {(NonNegativeIntegerArray|NonNegativeInteger)} [options.shape] - output array shape (overrides the input array's inferred shape)
* @param {string} [options.mode="throw"] - specifies how to handle indices which exceed array dimensions
* @param {ArrayLikeObject<string>} [options.submode=["throw"]] - specifies how to handle subscripts which exceed array dimensions on a per dimension basis
* @param {boolean} [options.readonly=false] - boolean indicating whether an array should be read-only
* @throws {TypeError} first argument must have a recognized data type
* @throws {TypeError} options argument must be an object
* @throws {TypeError} `dtype` option must be a supported data type
* @throws {TypeError} `order` option must be a supported order
* @throws {TypeError} `shape` option must be either a nonnegative integer or an array of nonnegative integers
* @throws {TypeError} must provide valid options
* @returns {ndarray} ndarray
*
* @example
* import getShape from '@stdlib/ndarray-shape';
* import getDType from '@stdlib/ndarray-dtype';
* import empty from '@stdlib/ndarray-empty';
*
* var x = empty( [ 2, 2 ], {
*     'dtype': 'generic'
* });
* // returns <ndarray>
*
* var y = truesLike( x );
* // returns <ndarray>[ [ true, true ], [ true, true ] ]
*
* var sh = getShape( y );
* // returns [ 2, 2 ]
*
* var dt = String( getDType( y ) );
* // returns 'generic'
*/
function truesLike( x ) {
	var options;
	var dtype;
	var order;
	var ndims;
	var opts;
	var len;
	var flg;
	var out;
	var st;
	var sh;

	if ( !isndarrayLike( x ) ) {
		throw new TypeError( format( 'null5t', x ) );
	}
	flg = false;
	opts = {};
	if ( arguments.length > 1 ) {
		options = arguments[ 1 ];
		if ( !isPlainObject( options ) ) {
			throw new TypeError( format( 'null2V', options ) );
		}
		if ( hasOwnProp( options, 'dtype' ) ) {
			dtype = options.dtype;
			if ( !isDataType( dtype ) ) {
				throw new TypeError( format( 'null4S', 'dtype', join( DTYPES, '", "' ), dtype ) );
			}
			flg = true;
		} else {
			dtype = getDType( x );
		}
		if ( hasOwnProp( options, 'shape' ) ) {
			sh = options.shape;
			if ( isNonNegativeInteger( sh ) ) {
				sh = [ sh ];
			} else if ( !isNonNegativeIntegerArray( sh ) && !isEmptyCollection( sh ) ) { // eslint-disable-line max-len
				throw new TypeError( format( 'nullDs', 'shape', sh ) );
			}
		} else {
			sh = getShape( x );
		}
		if ( hasOwnProp( options, 'order' ) ) {
			order = options.order;
		} else {
			order = getOrder( x );
		}
		if ( hasOwnProp( options, 'mode' ) ) {
			opts.mode = options.mode;
		}
		if ( hasOwnProp( options, 'submode' ) ) {
			opts.submode = options.submode;
		}
		if ( hasOwnProp( options, 'readonly' ) ) {
			opts.readonly = options.readonly;
		}
	} else {
		dtype = getDType( x );
		sh = getShape( x );
		order = getOrder( x );
	}
	if ( !flg && !isDataType( dtype ) ) {
		throw new TypeError( format( 'invalid argument. First argument must have one of the following data types: "%s". Value: `%s`.', join( DTYPES, '", "' ), dtype ) );
	}
	ndims = sh.length;
	if ( ndims > 0 ) {
		len = numel( sh );
		st = shape2strides( sh, order );
	} else {
		// For 0-dimensional arrays, the buffer should contain a single element...
		len = 1;
		st = [ 0 ];
	}
	out = new ndarray( dtype, buffer( dtype, len ), sh, st, 0, order, opts );
	fill( out, true );
	return out;
}


// EXPORTS //

export default truesLike;
